 */
function solve(nums) {
    // This problem is equivalent to finding the length of the Longest Increasing Subsequence (LIS)
    // with a specific property.
    //
    // Let the remaining subsequence be nums[i_1], nums[i_2], ..., nums[i_k] where i_1 < i_2 < ... < i_k.
    // In the new array, the element at index j (which is nums[i_{j+1}]) must satisfy
    // nums[i_{j+1}] = j.
    //
    // If we select a subsequence, and its new length is L, the elements must satisfy:
    // new_nums[0] = 0, new_nums[1] = 1, ..., new_nums[L-1] = L-1.
    //
    // Let the chosen subsequence elements from the original array be nums[i_0], nums[i_1], ..., nums[i_{L-1}].
    // For this to form all fixed points, we must have:
    // nums[i_0] = 0
    // nums[i_1] = 1
    // ...
    // nums[i_{L-1}] = L-1
    //
    // We are looking for the longest subsequence such that the j-th element of the subsequence is equal to j.
    // This simplifies to finding the longest subsequence of nums such that the k-th element of the subsequence
    // is equal to k-1 (using 0-based indexing for the subsequence position k-1).
    //
    // We can solve this greedily. We want to match 0, then 1, then 2, and so on, using elements from nums in increasing order of index.

    let target = 0; // The value we are currently looking for in the subsequence (0, 1, 2, ...)
    let count = 0;  // The number of fixed points found so far

    for (let i = 0; i < nums.length; i++) {
        // If the current element nums[i] matches the value we are looking for (target),
        // we select this element to be the next fixed point.
        if (nums[i] === target) {
            count++;
            target++; // Move to look for the next fixed point (target + 1)
        }
    }

    return count;
}
