    // [nums[i_1], nums[i_2], ..., nums[i_k]].
    // For this to have k fixed points, we must have:
    // nums[i_j] = j - 1 for j = 1 to k.
    // In 0-based indexing for j (from 0 to k-1), we need:
    // nums[i_j] = j.
    // This is the classic Longest Increasing Subsequence (LIS) problem,
    // but with a specific target value constraint: nums[i_j] must equal j.

    // Let's rephrase: we want to find the longest subsequence nums[i_0], nums[i_1], ..., nums[i_{k-1}]
    // such that i_0 < i_1 < ... < i_{k-1} AND nums[i_j] = j.

    // We can use a greedy approach or dynamic programming.
    // Since the required value for the j-th element of the subsequence is exactly j,
    // we just need to find the maximum k such that there exist indices
    // i_0 < i_1 < ... < i_{k-1} where nums[i_j] = j for all j=0 to k-1.

    let count = 0; // This will be our current index 'j' we are looking for (0, 1, 2, ...)
    let last_index = -1;

    // Iterate through the original array to find the required values in increasing order of index.
    for (let i = 0; i < nums.length; i++) {
        // We are looking for the value 'count' (which is the target index j).
        if (nums[i] === count) {
            // Found the element that should occupy position 'count' in the resulting array.
            // Since we are iterating through i in increasing order, this guarantees
            // that the index i is greater than the index chosen for 'count - 1'.
            count++;
        }
    }

    // 'count' now holds k, the maximum number of fixed points achievable.
    return count;
}
