function solve(nums) {
    // This problem is equivalent to finding the longest subsequence of nums
    // that is of the form [0, 1, 2, ..., k-1] for some k.
    // If we keep a subsequence at indices i_0, i_1, ..., i_{k-1} from the original array,
    // after deletion, the new array will have these elements at indices 0, 1, ..., k-1.
    // For this to be a set of fixed points, we must have:
    // nums[i_j] = j for all j in [0, k-1].

    // We are looking for the longest sequence of indices i_0 < i_1 < ... < i_{k-1} such that
    // nums[i_j] = j.

    let current_target = 0; // This is the value we are currently looking for (the required index in the new array)
    let fixed_points_count = 0;

    // Iterate through the original array
    for (let i = 0; i < nums.length; i++) {
        // Check if the current element nums[i] matches the next required value (current_target)
        if (nums[i] === current_target) {
            // If it matches, we decide to "keep" this element.
            // This element will become the fixed point at index 'current_target' in the new array.
            fixed_points_count++;
            // Now, we look for the next fixed point, which should be at index 'current_target + 1',
            // meaning the value must be 'current_target + 1'.
            current_target++;
        }
        // If nums[i] != current_target, we implicitly "delete" this element, as we are only looking
        // for elements that match the required sequence 0, 1, 2, ...
    }

    return fixed_points_count;
}
